import { readFileSync } from "node:fs";
import { quote } from "./claim-office.js";

type Item = { type: string; material: string; enchantment: number; cursed: boolean };
type Step = { op: string; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const STDIN_FD = 0;

const processStep = (step: Step, yearsWithMHPCO: number): object =>
  step.op === "quote"
    ? { premium: quote({ yearsWithMHPCO, items: step.items }) }
    : {};

const scenario: Scenario = JSON.parse(readFileSync(STDIN_FD, "utf-8"));
const results = scenario.steps.map((step) => processStep(step, scenario.customer.yearsWithMHPCO));
process.stdout.write(JSON.stringify({ results }));
